            for j in range(n - i - 1):
                if nums[j] > nums[j + 1]:
                    nums[j], nums[j + 1] = nums[j + 1], nums[j]
        return self.isSorted(nums)

    def isSorted(self, nums: list[int]) -> bool:
        for i in range(len(nums) - 1):
